// ============================================================
// HydraNet - Data Store (Zustand)
// Fetches data from API - No mock data
// ============================================================

import { create } from "zustand"

// Type imports for proper typing
import type { ReportStatus, ReportPriority, EntityStatus } from "@/lib/types"

// Types
export interface Utility {
  id: string
  name: string
  description: string | null
  managerId: string | null
  managerName: string
  status: EntityStatus
  dmasCount: number
  reportsCount: number
  createdAt: string
  updatedAt: string
}

export interface DMA {
  id: string
  name: string
  description: string | null
  utilityId: string
  utilityName: string
  managerId: string | null
  managerName: string
  status: EntityStatus
  branchesCount: number
  reportsCount: number
  engineersCount: number
  createdAt: string
  updatedAt: string
}

export interface Branch {
  id: string
  name: string
  dmaId: string
  utilityId: string
  status: EntityStatus
  createdAt: string
  updatedAt: string
}

export interface Engineer {
  id: string
  name: string
  email: string
  phone: string | null
  branchId: string
  branchName: string
  dmaId: string
  dmaName: string
  teamId: string | null
  teamName: string | null
  status: EntityStatus
  role: string
  assignedReports: number
  createdAt: string
  updatedAt: string
}

export interface Team {
  id: string
  name: string
  branchId: string
  branchName: string
  dmaId: string
  dmaName: string
  leaderId: string | null
  leaderName: string | null
  status: EntityStatus
  memberCount: number
  activeReports: number
  createdAt: string
  updatedAt: string
}

export interface Report {
  id: string
  trackingId: string
  description: string
  latitude: number
  longitude: number
  address: string | null
  photos: string[]
  priority: ReportPriority
  status: ReportStatus
  utilityId: string
  utilityName: string
  dmaId: string
  dmaName: string
  branchId: string | null
  branchName: string | null
  teamId: string | null
  teamName: string | null
  assignedEngineerId: string | null
  assignedEngineerName: string | null
  reporterName: string
  reporterPhone: string
  notes: string | null
  slaDeadline: string
  resolvedAt: string | null
  createdAt: string
  updatedAt: string
}

export interface ActivityLog {
  id: string
  action: string
  userId: string
  userName: string
  userRole: string
  entity: string
  entityId: string
  details: string | null
  utilityId: string | null
  dmaId: string | null
  timestamp: string
}

export interface Notification {
  id: string
  title: string
  message: string
  type: string
  read: boolean
  link: string | null
  userId: string
  createdAt: string
}

export interface User {
  id: string
  email: string
  name: string
  role: string
  phone: string | null
  status: string
}

interface DataState {
  // Data
  utilities: Utility[]
  dmas: DMA[]
  branches: Branch[]
  engineers: Engineer[]
  teams: Team[]
  reports: Report[]
  logs: ActivityLog[]
  notifications: Notification[]
  
  // Loading states
  isLoading: boolean
  initialized: boolean
  error: string | null

  // Fetch Actions
  initialize: () => Promise<void>
  fetchUtilities: () => Promise<void>
  fetchDMAs: (utilityId?: string) => Promise<void>
  fetchEngineers: (dmaId?: string) => Promise<void>
  fetchTeams: (dmaId?: string) => Promise<void>
  fetchReports: (filters?: { utilityId?: string; dmaId?: string; status?: string }) => Promise<void>
  fetchLogs: (utilityId?: string, dmaId?: string) => Promise<void>
  fetchNotifications: (userId: string) => Promise<void>
  getUnreadNotificationCount: () => number
  
  // CRUD: Utilities
  addUtility: (data: Partial<Utility>) => Promise<void>
  updateUtility: (id: string, data: Partial<Utility>) => Promise<void>
  deleteUtility: (id: string) => Promise<void>
  
  // CRUD: DMAs
  addDMA: (data: Partial<DMA>) => Promise<void>
  updateDMA: (id: string, data: Partial<DMA>) => Promise<void>
  deleteDMA: (id: string) => Promise<void>
  
  // CRUD: Reports
  addReport: (data: Partial<Report>) => Promise<void>
  updateReport: (id: string, data: Partial<Report>) => Promise<void>
  deleteReport: (id: string) => Promise<void>
  
  // CRUD: Engineers
  addEngineer: (data: Partial<Engineer>) => Promise<void>
  updateEngineer: (id: string, data: Partial<Engineer>) => Promise<void>
  deleteEngineer: (id: string) => Promise<void>
  
  // CRUD: Teams
  addTeam: (data: Partial<Team>) => Promise<void>
  updateTeam: (id: string, data: Partial<Team>) => Promise<void>
  deleteTeam: (id: string) => Promise<void>
  
  // CRUD: Branches
  addBranch: (data: Partial<Branch>) => Promise<void>
  updateBranch: (id: string, data: Partial<Branch>) => Promise<void>
  deleteBranch: (id: string) => Promise<void>
  fetchBranches: (dmaId?: string) => Promise<void>
  
  // Helper functions
  getDMAsByUtility: (utilityId: string) => DMA[]
  getReportsByUtility: (utilityId: string) => Report[]
  getReportsByDMA: (dmaId: string) => Report[]
  getTeamsByDMA: (dmaId: string) => Team[]
  getEngineersByDMA: (dmaId: string) => Engineer[]
  getBranchesByDMA: (dmaId: string) => Branch[]
  updateReportStatus: (id: string, status: string) => Promise<void>
  assignReport: (id: string, teamId: string, engineerId: string) => Promise<void>
}

export const useDataStore = create<DataState>((set, get) => ({
  // Initial state
  utilities: [],
  dmas: [],
  branches: [],
  engineers: [],
  teams: [],
  reports: [],
  logs: [],
  notifications: [],
  isLoading: false,
  initialized: false,
  error: null,

  // Initialize all data
  initialize: async () => {
    if (get().initialized) return
    set({ isLoading: true, error: null })

    try {
      await Promise.all([
        get().fetchUtilities(),
        get().fetchDMAs(),
        get().fetchEngineers(),
        get().fetchTeams(),
        get().fetchReports(),
        get().fetchLogs(),
      ])
      set({ isLoading: false, initialized: true })
    } catch (error) {
      set({ isLoading: false, error: "Failed to initialize data" })
      console.error("Initialization error:", error)
    }
  },

  // Fetch utilities
  fetchUtilities: async () => {
    try {
      const response = await fetch("/api/utilities")
      if (!response.ok) throw new Error("Failed to fetch utilities")
      const utilities = await response.json()
      set({ utilities })
    } catch (error) {
      console.error("Error fetching utilities:", error)
    }
  },

  // Fetch DMAs
  fetchDMAs: async (utilityId?: string) => {
    try {
      const url = utilityId ? `/api/dmas?utilityId=${utilityId}` : "/api/dmas"
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch DMAs")
      const dmas = await response.json()
      set({ dmas })
    } catch (error) {
      console.error("Error fetching DMAs:", error)
    }
  },

  // Fetch branches
  fetchBranches: async () => {
    try {
      const response = await fetch("/api/branches")
      if (!response.ok) throw new Error("Failed to fetch branches")
      const branches = await response.json()
      set({ branches })
    } catch (error) {
      console.error("Error fetching branches:", error)
    }
  },

  // Fetch engineers
  fetchEngineers: async (dmaId?: string) => {
    try {
      const url = dmaId ? `/api/engineers?dmaId=${dmaId}` : "/api/engineers"
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch engineers")
      const engineers = await response.json()
      set({ engineers })
    } catch (error) {
      console.error("Error fetching engineers:", error)
    }
  },

  // Fetch teams
  fetchTeams: async (dmaId?: string) => {
    try {
      const url = dmaId ? `/api/teams?dmaId=${dmaId}` : "/api/teams"
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch teams")
      const teams = await response.json()
      set({ teams })
    } catch (error) {
      console.error("Error fetching teams:", error)
    }
  },

  // Fetch reports
  fetchReports: async (filters?: { utilityId?: string; dmaId?: string; status?: string }) => {
    try {
      const params = new URLSearchParams()
      if (filters?.utilityId) params.set("utilityId", filters.utilityId)
      if (filters?.dmaId) params.set("dmaId", filters.dmaId)
      if (filters?.status) params.set("status", filters.status)

      const url = `/api/reports${params.toString() ? `?${params}` : ""}`
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch reports")
      const reports = await response.json()
      set({ reports })
    } catch (error) {
      console.error("Error fetching reports:", error)
    }
  },

  // Fetch logs
  fetchLogs: async (utilityId?: string, dmaId?: string) => {
    try {
      const params = new URLSearchParams()
      if (utilityId) params.set("utilityId", utilityId)
      if (dmaId) params.set("dmaId", dmaId)

      const url = `/api/logs${params.toString() ? `?${params}` : ""}`
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch logs")
      const logs = await response.json()
      set({ logs })
    } catch (error) {
      console.error("Error fetching logs:", error)
    }
  },

  // Fetch notifications
  fetchNotifications: async (userId: string) => {
    try {
      const response = await fetch(`/api/notifications?userId=${userId}`)
      if (!response.ok) throw new Error("Failed to fetch notifications")
      const notifications = await response.json()
      set({ notifications })
    } catch (error) {
      console.error("Error fetching notifications:", error)
    }
  },

  // Get unread notification count
  getUnreadNotificationCount: () => {
    return get().notifications.filter((n) => !n.read).length
  },

  // CRUD: Utilities
  addUtility: async (data: Partial<Utility>) => {
    try {
      const response = await fetch("/api/utilities", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to create utility")
      await get().fetchUtilities()
    } catch (error) {
      console.error("Error creating utility:", error)
      throw error
    }
  },

  updateUtility: async (id: string, data: Partial<Utility>) => {
    try {
      const response = await fetch(`/api/utilities/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to update utility")
      await get().fetchUtilities()
    } catch (error) {
      console.error("Error updating utility:", error)
      throw error
    }
  },

  deleteUtility: async (id: string) => {
    try {
      const response = await fetch(`/api/utilities/${id}`, {
        method: "DELETE",
      })
      if (!response.ok) throw new Error("Failed to delete utility")
      await get().fetchUtilities()
    } catch (error) {
      console.error("Error deleting utility:", error)
      throw error
    }
  },

  // CRUD: DMAs
  addDMA: async (data: Partial<DMA>) => {
    try {
      const response = await fetch("/api/dmas", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "Failed to create DMA")
      }
      await get().fetchDMAs()
    } catch (error) {
      console.error("Error creating DMA:", error)
      throw error
    }
  },

  updateDMA: async (id: string, data: Partial<DMA>) => {
    try {
      const response = await fetch(`/api/dmas/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "Failed to update DMA")
      }
      await get().fetchDMAs()
    } catch (error) {
      console.error("Error updating DMA:", error)
      throw error
    }
  },

  deleteDMA: async (id: string) => {
    try {
      const response = await fetch(`/api/dmas/${id}`, {
        method: "DELETE",
      })
      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "Failed to delete DMA")
      }
      await get().fetchDMAs()
    } catch (error) {
      console.error("Error deleting DMA:", error)
      throw error
    }
  },

  // CRUD: Reports
  addReport: async (data: Partial<Report>) => {
    try {
      const response = await fetch("/api/reports", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to create report")
      await get().fetchReports()
    } catch (error) {
      console.error("Error creating report:", error)
      throw error
    }
  },

  updateReport: async (id: string, data: Partial<Report>) => {
    try {
      const response = await fetch(`/api/reports/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to update report")
      await get().fetchReports()
    } catch (error) {
      console.error("Error updating report:", error)
      throw error
    }
  },

  deleteReport: async (id: string) => {
    try {
      const response = await fetch(`/api/reports/${id}`, {
        method: "DELETE",
      })
      if (!response.ok) throw new Error("Failed to delete report")
      await get().fetchReports()
    } catch (error) {
      console.error("Error deleting report:", error)
      throw error
    }
  },

  // CRUD: Engineers
  addEngineer: async (data: Partial<Engineer>) => {
    try {
      const response = await fetch("/api/engineers", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to create engineer")
      await get().fetchEngineers()
    } catch (error) {
      console.error("Error creating engineer:", error)
      throw error
    }
  },

  updateEngineer: async (id: string, data: Partial<Engineer>) => {
    try {
      const response = await fetch(`/api/engineers/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to update engineer")
      await get().fetchEngineers()
    } catch (error) {
      console.error("Error updating engineer:", error)
      throw error
    }
  },

  deleteEngineer: async (id: string) => {
    try {
      const response = await fetch(`/api/engineers/${id}`, {
        method: "DELETE",
      })
      if (!response.ok) throw new Error("Failed to delete engineer")
      await get().fetchEngineers()
    } catch (error) {
      console.error("Error deleting engineer:", error)
      throw error
    }
  },

  // CRUD: Teams
  addTeam: async (data: Partial<Team>) => {
    try {
      const response = await fetch("/api/teams", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to create team")
      await get().fetchTeams()
    } catch (error) {
      console.error("Error creating team:", error)
      throw error
    }
  },

  updateTeam: async (id: string, data: Partial<Team>) => {
    try {
      const response = await fetch(`/api/teams/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error("Failed to update team")
      await get().fetchTeams()
    } catch (error) {
      console.error("Error updating team:", error)
      throw error
    }
  },

  deleteTeam: async (id: string) => {
    try {
      const response = await fetch(`/api/teams/${id}`, {
        method: "DELETE",
      })
      if (!response.ok) throw new Error("Failed to delete team")
      await get().fetchTeams()
    } catch (error) {
      console.error("Error deleting team:", error)
      throw error
    }
  },

  // CRUD: Branches
  addBranch: async (data: Partial<Branch>) => {
    try {
      const response = await fetch("/api/branches", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      })
      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "Failed to create branch")
      }
      await get().fetchBranches()
    } catch (error) {
      console.error("Error creating branch:", error)
      throw error
    }
  },

  updateBranch: async (id: string, data: Partial<Branch>) => {
    try {
      const response = await fetch("/api/branches", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id, ...data }),
      })
      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "Failed to update branch")
      }
      await get().fetchBranches()
    } catch (error) {
      console.error("Error updating branch:", error)
      throw error
    }
  },

  deleteBranch: async (id: string) => {
    try {
      const response = await fetch(`/api/branches?id=${id}`, {
        method: "DELETE",
      })
      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "Failed to delete branch")
      }
      await get().fetchBranches()
    } catch (error) {
      console.error("Error deleting branch:", error)
      throw error
    }
  },

  // Helper functions
  getDMAsByUtility: (utilityId: string) => {
    return get().dmas.filter((d) => d.utilityId === utilityId)
  },

  getReportsByUtility: (utilityId: string) => {
    return get().reports.filter((r) => r.utilityId === utilityId)
  },

  getReportsByDMA: (dmaId: string) => {
    return get().reports.filter((r) => r.dmaId === dmaId)
  },

  getTeamsByDMA: (dmaId: string) => {
    return get().teams.filter((t) => t.dmaId === dmaId)
  },

  getEngineersByDMA: (dmaId: string) => {
    return get().engineers.filter((e) => e.dmaId === dmaId)
  },

  getBranchesByDMA: (dmaId: string) => {
    return get().branches.filter((b) => b.dmaId === dmaId)
  },

  updateReportStatus: async (id: string, status: string) => {
    try {
      const response = await fetch(`/api/reports/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status }),
      })
      if (!response.ok) throw new Error("Failed to update report status")
      await get().fetchReports()
    } catch (error) {
      console.error("Error updating report status:", error)
      throw error
    }
  },

  assignReport: async (id: string, teamId: string, engineerId: string) => {
    try {
      const teams = get().teams
      const engineers = get().engineers
      const team = teams.find((t) => t.id === teamId)
      const engineer = engineers.find((e) => e.id === engineerId)
      
      const response = await fetch(`/api/reports/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          teamId,
          assignedEngineerId: engineerId,
          teamName: team?.name,
          assignedEngineerName: engineer?.name,
          status: "assigned",
        }),
      })
      if (!response.ok) throw new Error("Failed to assign report")
      await get().fetchReports()
    } catch (error) {
      console.error("Error assigning report:", error)
      throw error
    }
  },
}))
